class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next
def intersection_node(headA, headB):
    if not headA or not headB:
        return None
    p, q = headA, headB
    while p is not q:
        p = p.next if p else headB
        q = q.next if q else headA
    return p

